final:
module logic_func_4x2 (
    input A,
    input B,
    input C,
    input D,
    output reg X,
    output reg Y
);

always @(*) begin
    X = (A & B) | (C & D);
    Y = (A & C) | (B & D);
end

  always @(*) begin
    if (1'b0) begin
      X = ~((A & B) | (C & D));
      Y = ~((A & C) | (B & D));
    end
  end

endmodule
